-- Sprint 17A: controlled AI configuration, governance and tenant-scoped logs.
create table public.ai_agents (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_key text not null,agent_type text not null check(agent_type in ('dashboard_analyst','report_writer','general_chat','attendance_inbox')),name text not null,description text,status text not null default 'draft' check(status in ('draft','active','inactive','archived')),module_key text,behavior_profile text,system_instructions text,guardrails jsonb not null default '{}'::jsonb,model_provider text not null default 'openai',model_name text,temperature numeric not null default .2 check(temperature>=0 and temperature<=2),max_output_tokens integer not null default 1200 check(max_output_tokens>=100 and max_output_tokens<=8000),response_schema jsonb not null default '{}'::jsonb,trigger_config jsonb not null default '{}'::jsonb,created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz,unique(tenant_id,agent_key));
create table public.ai_tools (id uuid primary key default gen_random_uuid(),tool_key text not null unique,name text not null,description text,tool_type text not null default 'controlled_function',module_key text,input_schema jsonb not null default '{}'::jsonb,output_schema jsonb not null default '{}'::jsonb,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.ai_agent_tools (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid not null references public.ai_agents(id) on delete cascade,tool_id uuid not null references public.ai_tools(id) on delete cascade,is_enabled boolean not null default false,config jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(tenant_id,agent_id,tool_id));
create table public.ai_runs (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid references public.ai_agents(id) on delete set null,run_type text not null check(run_type in ('dashboard_analysis','report_narrative','general_chat','attendance_inbox','manual_test')),trigger_type text not null default 'manual' check(trigger_type in ('manual','dashboard_publish','dashboard_refresh','report_generate','chat_message','inbox_message')),status text not null default 'pending' check(status in ('pending','processing','completed','failed','cancelled')),input_snapshot jsonb not null default '{}'::jsonb,output_json jsonb,error_message text,model_provider text,model_name text,input_tokens integer not null default 0,output_tokens integer not null default 0,total_tokens integer not null default 0,estimated_cost_cents numeric,requested_by uuid references auth.users(id),started_at timestamptz,finished_at timestamptz,created_at timestamptz not null default now());
create table public.ai_tool_calls (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,ai_run_id uuid not null references public.ai_runs(id) on delete cascade,tool_id uuid references public.ai_tools(id) on delete set null,tool_key text not null,input_json jsonb not null default '{}'::jsonb,output_json jsonb,status text not null default 'pending' check(status in ('pending','completed','failed','blocked')),error_message text,duration_ms integer,created_at timestamptz not null default now(),finished_at timestamptz);
create table public.ai_usage_logs (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid references public.ai_agents(id) on delete set null,ai_run_id uuid references public.ai_runs(id) on delete cascade,provider text not null default 'openai',model_name text,input_tokens integer not null default 0,output_tokens integer not null default 0,total_tokens integer not null default 0,estimated_cost_cents numeric,created_at timestamptz not null default now());
create table public.ai_feedback (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid references public.ai_agents(id) on delete cascade,ai_run_id uuid references public.ai_runs(id) on delete cascade,user_id uuid references auth.users(id),rating integer check(rating is null or rating between 1 and 5),comment text,created_at timestamptz not null default now());
create index on public.ai_agents(tenant_id,agent_type,status); create index on public.ai_agent_tools(tenant_id,agent_id); create index on public.ai_runs(tenant_id,agent_id,created_at desc); create index on public.ai_tool_calls(tenant_id,ai_run_id); create index on public.ai_usage_logs(tenant_id,agent_id,created_at desc); create index on public.ai_feedback(tenant_id,agent_id,created_at desc);
do $$ declare t text; begin foreach t in array array['ai_agents','ai_agent_tools','ai_runs','ai_tool_calls','ai_usage_logs','ai_feedback'] loop execute format('alter table public.%I enable row level security',t); execute format('create policy "tenant members %s" on public.%I for all to authenticated using (public.is_member_of_tenant(tenant_id)) with check (public.is_member_of_tenant(tenant_id))',t,t); end loop; end $$;
alter table public.ai_tools enable row level security; create policy "authenticated read ai tools" on public.ai_tools for select to authenticated using (true);
insert into public.ai_tools(tool_key,name,description,module_key) values ('dashboard.get_snapshot','Obter snapshot de dashboard','Retorna snapshot tratado de dashboard publicado.','core'),('dashboard.get_widget_results','Obter resultados dos widgets do dashboard','Retorna resultados determinísticos dos widgets exibidos.','core'),('reports.get_job_snapshot','Obter snapshot de relatório','Retorna render_snapshot/data_snapshot de um relatório já gerado.','core'),('indicators.get_result','Obter resultado de indicador','Executa ou consulta indicador validado, usando filtros controlados.','core'),('indicators.list_available','Listar indicadores disponíveis','Lista indicadores nativos e personalizados permitidos ao tenant.','core'),('native_filters.list_options','Listar opções de filtros nativos','Lista opções válidas de filtros tratados.','core'),('treated_data.get_summary','Obter resumo de dados tratados','Retorna resumos agregados de dados tratados, sem SQL livre.','core') on conflict(tool_key) do update set name=excluded.name,description=excluded.description,module_key=excluded.module_key,updated_at=now();
insert into public.permissions(key,name,module_key,resource,action,description) values ('agents.view','Visualizar agentes','agents','agents','view','Permite visualizar agentes.'),('agents.configure','Configurar agentes','agents','agents','configure','Permite criar e editar agentes.'),('agents.manage_tools','Gerenciar ferramentas de agentes','agents','agents','manage_tools','Permite gerenciar ferramentas controladas.'),('agents.run','Executar teste de agente','agents','agents','run','Permite executar testes manuais.'),('agents.view_runs','Visualizar execuções de agentes','agents','agents','view_runs','Permite visualizar execuções.'),('agents.view_usage','Visualizar consumo de IA','agents','agents','view_usage','Permite visualizar consumo.'),('agents.feedback','Enviar feedback de IA','agents','agents','feedback','Permite registrar feedback.') on conflict(key) do update set name=excluded.name,description=excluded.description,updated_at=now();
insert into public.role_permissions(tenant_id,role_id,permission_id) select r.tenant_id,r.id,p.id from public.roles r cross join public.permissions p where r.key in ('owner','admin','super_admin','administrador') and p.key like 'agents.%' on conflict do nothing;
